import {
  Accordion,
  AccordionContent,
  AccordionItem,
  AccordionTrigger,
} from "@/components/ui/accordion";
import { cn } from "@/lib/utils";
import { MinusIcon, PlusIcon } from "lucide-react";

const FAQ_DATA = [
  {
    question: "How do I get started with the component library?",
    answer:
      "Getting started is simple — install the package, import the components you need, and drop them into your project. Each component follows shadcn/ui conventions and works seamlessly with your existing setup.",
  },
  {
    question: "Can I customize the styles to match my brand?",
    answer:
      "Absolutely. All components are built with Tailwind CSS and shadcn design tokens, so you can override colors, spacing, and typography via your globals.css or by passing a className prop directly to any component.",
  },
  {
    question: "Are the components accessible by default?",
    answer:
      "Yes. Every component is built on top of Radix UI primitives, which handle keyboard navigation, focus management, and ARIA attributes out of the box, ensuring WCAG-compliant accessibility from day one.",
  },
];

const AccordionLineDemo = () => (
  <div className="flex items-center justify-center w-full max-w-lg">
    <Accordion defaultValue={["item-0"]} className="w-full flex flex-col border-x border-border">
      {FAQ_DATA.map((faq, index) => (
        <AccordionItem
          key={`item-${index}`}
          value={`item-${index}`}
          className={cn(
            "relative flex flex-col group/item transition-colors first:border-t last:border-b animate-in fade-in slide-in-from-bottom-6 duration-700 fill-mode-both",
            index === 0 && "delay-100",
            index === 1 && "delay-200",
            index === 2 && "delay-300"
          )}
        >
          <AccordionTrigger className="p-6 gap-5 items-center text-base font-medium hover:no-underline **:data-[slot=accordion-trigger-icon]:hidden cursor-pointer">
            {faq.question}
            <PlusIcon className="w-4 h-4 shrink-0 group-aria-expanded/accordion-trigger:hidden" />
            <MinusIcon className="w-4 h-4 shrink-0 hidden group-aria-expanded/accordion-trigger:inline" />
          </AccordionTrigger>
          <AccordionContent className="px-6 pb-6 text-muted-foreground">
            {faq.answer}
          </AccordionContent>
          <span className="absolute top-0 left-0 right-0 h-0.5 bg-blue-500 scale-x-0 group-data-open/item:scale-x-100 transition-transform duration-300 origin-left" />
        </AccordionItem>
      ))}
    </Accordion>
  </div>
);

export default AccordionLineDemo;
